#1. 名言： “计算机科学领域的任何问题都可以通过增加一个间接的中间层来解决”。 2.Tcp/ip产生背景:“通过因特网完成有效数据传输”，中遇到的不同领域（硬件、系统、路由算法）等划分成小问题后，出现多种协议，它们通过层次结构简历紧密联系。 ###2.1 链路层：网卡等网络硬件设备及驱动程序，专门定义LAN,WAN,MAN等网络标准。 ###2.2 IP层： IP本身是面向消息的，不可靠的协议。每次传输数据时会帮我们选择路径，但并不一致。如果传输中发生路径错误，则选择其他路径，但如果发生数据丢失或错误，则无法解决。 2.3TCP/UDP层：TCP协议确认后向不可靠的IP协议赋予可靠性。TCP每发送一个数据都会和接收端确认，如果接收端确认收到才发下一个数据，否则重新发送。 2.4应用层：网络编程的大部分内容就是设计并实现应用层协议。如：超文本传输协议HTTP,邮件传送协议SMTP等。 3.TCP默认函数调用顺序：- 3.1 服务端顺序如下：123456socket() //创建套接字 bind() //分配套接字地址 listen() //等待连接请求状态 accept() //允许连接read()/write() //数据交换 close() //断开连接 listen() ： 12345#include &lt;sys/socket.h&gt;int listen(int sock, int backlog); //sock：服务端套接字文件描述符(监听套接字) //backlog：连接请求等待队列的大小。即客服端请求的连接会先放入这个队列中排队，等待处理。如果队列长度为5，则表示最多使5个连接请求进入队列。 accept()： 1234567#include &lt;sys/socket.h&gt;int accept(int sock, struct sockaddr *addr, socklen_t *addrlen); //sock：服务端套接字的文件描述符 //addr：保存发起连接请求的客服端地址信息的变量 //addrlen：保存客服端地址长度 //注：这个函数就是受理连接请求等待队列中待处理的客服端连接请求。它是个阻断函数，只有队列中有请求才会返回，并在其内部自动产生用于数据I/O的套接字 - 3.2客服端顺序如下：1234socket() // 创建套接字 connect() //请求连接(要在listen()调用之后) read()/write() //数据交换 close() //断开连接 connect() 123456#include &lt;sys/socket.h&gt;int connect(int sock, struct sockaddr *servaddr, socklen_t addrlen); sock：客户端套接字文件描述符 servaddr：保存目标服务端地址信息的变量 addrlen：服务端地址变量长度 注释：accept()要获取客户端的地址信息，但客户端没有bind()分配地址这一步，那么客户端套接字地址信息在哪呢？其实是在调用connect()时，由操作系统自动分配的，IP用的主机的IP，端口随机。 write() 12345#include &lt;unistd.h&gt; ssize_t write(int fd, const void *buf, size_t nbytes); fd：数据传输对象的文件描述符 buf：保存要传输数据的缓冲地址值 nbytes：要传输数据的字节数 read() 12345#include &lt;unistd.h&gt;ssize_t read(int fd, void *buf, size_t nbytes); fd：数据接收数据的文件描述符 buf：保存要接收数据的缓冲地址值 nbytes：要接收数据的字节数 4.迭代服务端问题思考：之前是单一提供服务。怎么使服务器向其它用户提供服务。 解决：插入循环语句反复调用accept()，利用read()、write()交换数据。 好处：一个客户端close()后，服务端还可以为其它客户服务。但同一时间只能一个客户交换数据。 5.代码实现：- 服务端代码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;string.h&gt;#include &lt;unistd.h&gt;#include &lt;arpa/inet.h&gt;#include &lt;sys/socket.h&gt;#define BUF_SIZE 1024void error_handling(char *message)&#123; fputs(message, stderr); fputc(&apos;
&apos;, stderr); exit(1);&#125;int main(int argc, const char * argv[]) &#123; int serv_sock, clnt_sock; char message[BUF_SIZE]; int str_len, i; struct sockaddr_in serv_adr, clnt_adr; socklen_t clnt_adr_sz; if(argc != 2) &#123; printf(&quot;Usage: %s &lt;port&gt; 
&quot;, argv[0]); exit(1); &#125; serv_sock = socket(PF_INET, SOCK_STREAM, 0); if(serv_sock == -1) error_handling(&quot;socket() error&quot;); memset(&amp;serv_adr, 0, sizeof(serv_adr)); serv_adr.sin_family = AF_INET; serv_adr.sin_addr.s_addr = htonl(INADDR_ANY); serv_adr.sin_port = htons(atoi(argv[1])); if(bind(serv_sock, (struct sockaddr *) &amp;serv_adr, sizeof(serv_adr)) == -1) error_handling(&quot;bind() error&quot;); if(listen(serv_sock, 5) == -1) error_handling(&quot;listen() error&quot;); clnt_adr_sz = sizeof(clnt_adr); for (i = 0; i &lt; 5; i++) &#123; clnt_sock = accept(serv_sock, (struct sockaddr *) &amp;clnt_adr, &amp;clnt_adr_sz); if(clnt_sock == -1) error_handling(&quot;accept() error&quot;); else printf(&quot;Connected client %d 
&quot;, i+1); while ((str_len = read(clnt_sock, message, BUF_SIZE)) != 0) write(clnt_sock, message, str_len); close(clnt_sock); &#125; close(serv_sock); return 0;&#125; - 客户端代码1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;string.h&gt;#include &lt;unistd.h&gt;#include &lt;arpa/inet.h&gt;#include &lt;sys/socket.h&gt;#define BUF_SIZE 1024void error_handling(char *message)&#123; fputs(message, stderr); fputc(&apos;
&apos;, stderr); exit(1);&#125;int main(int argc, const char * argv[]) &#123; int sock; char message[BUF_SIZE]; int str_len, recv_len, recv_cnt; struct sockaddr_in serv_adr; if(argc != 3) &#123; printf(&quot;Usage: %s &lt;IP&gt; &lt;port&gt; 
&quot;, argv[0]); exit(1); &#125; sock = socket(PF_INET, SOCK_STREAM, 0); if(sock == -1) error_handling(&quot;socket() error&quot;); memset(&amp;serv_adr, 0, sizeof(serv_adr)); serv_adr.sin_family = AF_INET; serv_adr.sin_addr.s_addr = inet_addr(argv[1]); serv_adr.sin_port = htons(atoi(argv[2])); if (connect(sock, (struct sockaddr *) &amp;serv_adr, sizeof(serv_adr)) == -1) error_handling(&quot;connect() error&quot;); else puts(&quot;Connected ...............&quot;); while (1) &#123; fputs(&quot;Input message(Q to quit): &quot;, stdout); fgets(message, BUF_SIZE, stdin); if (!strcmp(message, &quot;q
&quot;) || !strcmp(message, &quot;Q
&quot;)) break; str_len = write(sock, message, strlen(message)); /*这里需要循环读取，因为TCP没有数据边界，不循环读取可能出现一个字符串一次发送 但分多次读取而导致输出字符串不完整*/ recv_len = 0; while (recv_len &lt; str_len) &#123; recv_cnt = read(sock, &amp;message[recv_len], BUF_SIZE - 1); if(recv_cnt == -1) error_handling(&quot;read() error&quot;); recv_len += recv_cnt; &#125; message[recv_len] = 0; printf(&quot;Message from server: %s&quot;, message); &#125; close(sock); return 0;&#125; 注意：每次调用read,write都会以字符串为单位执行实际的I/O操作。但因为TCP不存在数据边界，因此多次调用的write传递的字符串可能一次性的传递到服务端上，而客户端也可能一次性接受到多个字符串，另外，服务端要传输的数据太大，操作系统可能把数据分包发送到客户端，而客户端也可能没有在收到全部数据包时，就调用read()函数。 未完待续。。。。

1. 服务端接收连接请求的套接字创建过程如下:1.1调用socket函数创建套接字。12345#include &lt;sys/socket.h&gt; int socket(int domain, int type, int protocol); 成功返回文件描述符(整型)，失败返回-1。 domain(协议族)： PF_INET：ipv4)，PF_INET6：ipv6。 type(数据传输类型)：SOCK_STREAM：TCP ，SOCK_DGRAM：UDP。 protocol(具体协议)： IPPROTO_TCP， IPPROTO_UDP，0. 1.2 调用bind函数分配IP地址和端口号。1int bind(int sockfd, struct sockaddr *myaddr, socklen_t addrlen); 成功返回0，失败返回-1。 ###1.3 调用listen函数转为可接收请求状态。 1int listen(int sockfd, int backlog);成功返回0，失败返回-1。 1.4调用accept函数受理连接请求。1int accept(int sockfd, struct sockaddr *addr, socklen_t *addrlen);成功返回文件描述符，失败返回-1。 #2. 基于Linux的文件操作 ###2.1 打开文件： 1int open(const char *path, int flag); –&gt; (Linux上对应socket(…)函数) 2.2关闭文件或套接字：1int close(int fd); –&gt;(Windows上对应closesocket(SOCKET S)函数) 2.3将数据写入文件或传递数据：12ssize_t write(int fd, const void *buf, size_t nbytes); ###2.4 读取文件中数据或接收数据： 1ssize_t read(int fd, void *buf, size_t nbytes); 3.基于Windows平台的实现###3.1 Winsock库初始化： 123456789int main(int argc, char *argv[])&#123; WSADATA wsaData; ... if(WSAStartup(MAKEWORD(1,2), &amp;wsaData) != 0) ErrorHandling(&quot;WSAStartup() error!&quot;); ... return 0;&#125; 3.2Winsock头文件123456#include &lt;winsock2.h&gt;int WSAStartup(WORD wVersionRequested,LPWSADATA lpWSAData) WORD wVersionRequested(winsock版本)： MAKEWORD(1,2)//主版本1，副版本2，返回0x0201 MAKEWORD(2,2)//主版本2，副版本2，返回0x0202 LPWSADATA lpWSAData(传入的WSADATA型结构体变量地址)：&amp;wsaData 3.3 释放Winsock库：1int WSACleanup(void); //返回0成功，失败返回SOCKET_ERROR 3.4Winsock数据传输函数：1int send(SOCKET s, const char *buf, int len, int flags); 3.5Winsock数据接收函数：1int recv(SOCKET s, const char *buf, int len, int flags); #4. server.c 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;string.h&gt;#include &lt;unistd.h&gt;#include &lt;arpa/inet.h&gt;#include &lt;sys/socket.h&gt;void error_handling(char *message)；int main(int argc, const char * argv[]) &#123; //argc记录输入命令的个数。argv[]存放命令的位置。 int serv_sock; int clnt_sock; struct sockaddr_in serv_addr; struct sockaddr_in clnt_addr; socklen_t clnt_addr_size; char message[] = &quot;Hello World!&quot;; if(argc != 2) &#123; printf(&quot;Usage：%s &lt;port&gt;
&quot;, argv[0]); exit(1); &#125; serv_sock = socket(PF_INET, SOCK_STREAM, 0);//创建套接字。 if(serv_sock == -1) error_handling(&quot;socket() error&quot;); memset(&amp;serv_addr, 0, sizeof(serv_addr)); 初始化serv_addr。 serv_addr.sin_family = AF_INET; serv_addr.sin_addr.s_addr = htonl(INADDR_ANY); serv_addr.sin_port = htons(atoi(argv[1])); if(bind(serv_sock, (struct sockaddr*) &amp;serv_addr, sizeof(serv_addr)) == -1)//分配ip和端口。 error_handling(&quot;bind() error&quot;); if(listen(serv_sock, 5) == -1) //将套接字转化为可接受状态。 error_handling(&quot;listen() error&quot;); clnt_addr_size = sizeof(clnt_addr); //如果没有收到请求，则不返回，只到有连接请求为止 clnt_sock = accept(serv_sock, (struct sockaddr*) &amp;clnt_addr, &amp;clnt_addr_size);//使可以接受客户端连接请求。 if(clnt_sock == -1) error_handling(&quot;accept() error&quot;); write(clnt_sock, message, sizeof(message)); close(clnt_sock); //关闭客户端套接字。 close(serv_sock);//关闭服务端套接字。 return 0;&#125;void error_handling(char *message)&#123; fputs(message, stderr); fputc(&apos;
&apos;, stderr); exit(1);&#125; client.c1234567891011121314151617181920212223242526272829303132333435363738394041424344454647#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;string.h&gt;#include &lt;unistd.h&gt;#include &lt;arpa/inet.h&gt;#include &lt;sys/socket.h&gt;void error_handling(char *message)&#123; fputs(message, stderr); fputc(&apos;
&apos;, stderr); exit(1);&#125;int main(int argc, const char * argv[]) &#123; int sock; struct sockaddr_in serv_addr; char message[30]; int str_len; if(argc != 3) &#123; printf(&quot;Usage: %s &lt;IP&gt; &lt;port&gt;
&quot;, argv[0]); exit(1); &#125; sock = socket(PF_INET, SOCK_STREAM, 0); if(sock == -1) error_handling(&quot;socket() error&quot;); memset(&amp;serv_addr, 0, sizeof(serv_addr)); serv_addr.sin_family = AF_INET; serv_addr.sin_addr.s_addr = inet_addr(argv[1]); serv_addr.sin_port = htons(atoi(argv[2])); if(connect(sock, (struct sockaddr*) &amp;serv_addr, sizeof(serv_addr)) == -1) error_handling(&quot;connect() error&quot;); str_len = read(sock, message, sizeof(message) - 1); if(str_len == -1) error_handling(&quot;read() error&quot;); printf(&quot;Message from server: %s 
&quot;, message); close(sock); return 0;&#125;
